    assign cpu_wr_32b_aw.len    = fub_axi_awlen;
    assign cpu_wr_32b_aw.size   = fub_axi_awsize;
    assign cpu_wr_32b_aw.burst  = fub_axi_awburst;
    assign cpu_wr_32b_aw.lock   = fub_axi_awlock;
