    always_comb begin
        fub_axi_wready = 1'b0;
        case (w_slave_select)
            2'b01: begin  // Slave 0 (32b)
                fub_axi_wready = cpu_wr_32b_wready;
            end
            2'b10: begin  // Slave 1 (32b)
                fub_axi_wready = cpu_wr_32b_wready;
            end
            default: begin
                // No active W transaction
            end
        endcase
    end

    // Write response MUX (B channel - uses b_slave_select FIFO head)
    always_comb begin
        fub_axi_bid = 4'd0;
        fub_axi_bresp = 2'b00;
        fub_axi_bvalid = 1'b0;

        case (b_slave_select)
            2'b01: begin  // Slave 0 (32b)
                fub_axi_bid = cpu_wr_32b_b.id;
                fub_axi_bresp = cpu_wr_32b_b.resp;
                fub_axi_bvalid = cpu_wr_32b_bvalid;
