                fub_axi_bid = cpu_wr_32b_b.id;
                fub_axi_bresp = cpu_wr_32b_b.resp;
                fub_axi_bvalid = cpu_wr_32b_bvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

